    'msg.coa_already':        'Le CoA est déjà en votre possession.',
    'msg.gmp_verified':       'Terminal GMP : Matériau RM-4471 VÉRIFIÉ ✓. Accès à la ligne de production accordé.',
    'msg.gmp_needs_coa':      'Le terminal GMP nécessite un certificat d\'analyse. Trouvez-le d\'abord.',
